// ── Server-side validation ─────────────────────────────────
// Mirrors the frontend rules in patient-form/index.html.
// Accepts body both as $json (raw), $json.body, and URL-encoded webhook payloads.
// Clinical context is intentionally captured later in the doctor dashboard.

const body = $input.first().json.body || $input.first().json;

const errors = [];
const clean = (value, max = 1000) => String(value || '').trim().slice(0, max);

const patientName        = clean(body.patient_name, 100);
const phoneRaw           = clean(body.phone_number, 20);
const dob                = clean(body.dob, 20);
const sex                = clean(body.sex, 20);
const hospitalName       = clean(body.hospital_name, 160);
const doctorName         = clean(body.doctor_name, 160);
const visitDate          = clean(body.visit_date, 20);
const followUpRequired   = clean(body.follow_up_required, 10);
const followUpDate       = clean(body.follow_up_date, 20);

const ISO_DATE = /^\d{4}-\d{2}-\d{2}$/;
const PHONE_RE = /^[0-9]{10}$/;
const today    = new Date(); today.setHours(0,0,0,0);


function rateLimitRequest(scope, key, limit, windowMs) {
  if (!key) return null;
  try {
    const store = typeof $getWorkflowStaticData === 'function' ? $getWorkflowStaticData('global') : null;
    if (!store) return null;
    store._rateLimits = store._rateLimits || {};
    const now = Date.now();
    const bucketKey = scope + ':' + key;
    const bucket = Array.isArray(store._rateLimits[bucketKey]) ? store._rateLimits[bucketKey] : [];
    const recent = bucket.filter(ts => now - ts < windowMs);
    recent.push(now);
    store._rateLimits[bucketKey] = recent;
    return recent.length > limit ? Math.ceil((windowMs - (now - recent[0])) / 1000) : null;
  } catch (_) {
    return null;
  }
}

const headers = $input.first().json.headers || {};
const header = name => headers[name] || headers[name.toLowerCase()] || headers[name.toUpperCase()] || '';
const clientIp = String(header('x-forwarded-for') || header('x-real-ip') || 'unknown').split(',')[0].trim();
const ipRetryAfter = rateLimitRequest('patient-form-ip', clientIp, 80, 15 * 60 * 1000);
const phoneRetryAfter = PHONE_RE.test(phoneRaw) ? rateLimitRequest('patient-form-phone', phoneRaw, 8, 15 * 60 * 1000) : null;
if (ipRetryAfter || phoneRetryAfter) {
  errors.push('too_many_requests: please wait before submitting again');
}

// Required fields
if (!patientName || patientName.length < 2)
  errors.push('patient_name: required, minimum 2 characters');

if (!PHONE_RE.test(phoneRaw))
  errors.push('phone_number: must be exactly 10 digits (no +91)');

if (!hospitalName)
  errors.push('hospital_name: required');

if (!doctorName)
  errors.push('doctor_name: required');

if (!visitDate || !ISO_DATE.test(visitDate))
  errors.push('visit_date: required, format YYYY-MM-DD');
else if (new Date(visitDate + 'T00:00:00') > today)
  errors.push('visit_date: cannot be in the future');

if (!['Yes','No'].includes(followUpRequired))
  errors.push('follow_up_required: must be Yes or No');

// Conditional follow-up date
if (followUpRequired === 'Yes') {
  if (!followUpDate || !ISO_DATE.test(followUpDate))
    errors.push('follow_up_date: required when follow_up_required is Yes, format YYYY-MM-DD');
  else if (visitDate && followUpDate <= visitDate)
    errors.push('follow_up_date: must be strictly after visit_date');
}

// Optional field validation
if (sex && !['Male','Female','Other'].includes(sex))
  errors.push('sex: must be Male, Female, or Other');

if (dob) {
  if (!ISO_DATE.test(dob))
    errors.push('dob: format must be YYYY-MM-DD');
  else if (new Date(dob + 'T00:00:00') >= today)
    errors.push('dob: must be a past date');
}

if (errors.length > 0) {
  return [{ json: { _valid: false, _errors: errors } }];
}

// Normalise phone to E.164 (+91). Phone is the primary business key for patients.
const phone = '+91' + phoneRaw;

return [{
  json: {
    _valid:            true,
    _errors:           [],
    patient_name:      patientName,
    phone:             phone,
    dob:               dob  || null,
    sex:               sex  || null,
    clinic_name:       hospitalName,
    doctor_name:       doctorName,
    visit_date:        visitDate,
    follow_up_required: followUpRequired,
    follow_up_date:    followUpRequired === 'Yes' ? followUpDate : null,
  }
}];

// Pull validated fields from the Validate node
const v = $('Validate and Normalise').first().json;

// Generate PAT-XXXX code from current patient count
const count = $input.first().json.total || 0;
const patientCode = 'PAT-' + String(count + 1).padStart(4, '0');

return [{
  json: {
    patient_code:       patientCode,
    name:               v.patient_name,
    phone:              v.phone,
    dob:                v.dob,
    sex:                v.sex,
    clinic_name:        v.clinic_name,
    doctor_name:        v.doctor_name,
    visit_date:         v.visit_date,
    follow_up_required: v.follow_up_required,
    follow_up_date:     v.follow_up_date,
  }
}];
